import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronDown, Upload, Trash2, Edit2, Plus, LogOut } from 'lucide-react';
import './AdminDashboard.css';

const API_BASE = 'http://localhost:5000';

export default function AdminDashboard() {
  const [authenticated, setAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const [activeTab, setActiveTab] = useState('products');
  const [data, setData] = useState(null);
  const [expanding, setExpanding] = useState(null);

  // ---------- Auth ----------
  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'verify', password }),
      });
      if (res.ok) {
        setAuthenticated(true);
        fetchData();
      } else {
        setError('Invalid password');
      }
    } catch (e) {
      setError('Network error: ' + e.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchData = async () => {
    try {
      const res = await fetch(`${API_BASE}/api/getData`);
      setData(await res.json());
    } catch (e) {
      setError('Failed to load data: ' + e.message);
    }
  };

  useEffect(() => {
    if (authenticated) fetchData();
  }, [authenticated]);

  if (!authenticated) {
    return (
      <div className="admin-login-container">
        <motion.div 
          className="admin-login-card"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
        >
          <h1>Admin Dashboard</h1>
          <form onSubmit={handleLogin}>
            <input
              type="password"
              placeholder="Enter admin password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              disabled={loading}
            />
            <button type="submit" disabled={loading}>
              {loading ? 'Verifying...' : 'Login'}
            </button>
          </form>
          {error && <p className="error-message">{error}</p>}
        </motion.div>
      </div>
    );
  }

  return (
    <div className="admin-container">
      <div className="admin-header">
        <h1>Admin Dashboard</h1>
        <button 
          className="logout-btn"
          onClick={() => {
            setAuthenticated(false);
            setPassword('');
            setData(null);
          }}
        >
          <LogOut size={20} /> Logout
        </button>
      </div>

      <div className="admin-tabs">
        {['products', 'gallery', 'clients'].map(tab => (
          <button
            key={tab}
            className={`tab-btn ${activeTab === tab ? 'active' : ''}`}
            onClick={() => setActiveTab(tab)}
          >
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      {error && <div className="error-alert">{error}</div>}

      <AnimatePresence mode="wait">
        {activeTab === 'products' && data && (
          <motion.div 
            key="products"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <ProductsTab data={data} password={password} setError={setError} fetchData={fetchData} />
          </motion.div>
        )}
        {activeTab === 'gallery' && data && (
          <motion.div 
            key="gallery"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <GalleryTab data={data} password={password} setError={setError} fetchData={fetchData} />
          </motion.div>
        )}
        {activeTab === 'clients' && data && (
          <motion.div 
            key="clients"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <ClientsTab data={data} password={password} setError={setError} fetchData={fetchData} />
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

// ---------- PRODUCTS TAB ----------
function ProductsTab({ data, password, setError, fetchData }) {
  const [expandedCat, setExpandedCat] = useState(null);
  const [newCatName, setNewCatName] = useState('');
  const [addingCat, setAddingCat] = useState(false);

  const addCategory = async () => {
    if (!newCatName.trim()) return;
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'addCategory',
          password,
          category: { name: newCatName, subProducts: [] },
        }),
      });
      if (res.ok) {
        setNewCatName('');
        fetchData();
      } else {
        setError('Failed to add category');
      }
    } catch (e) {
      setError(e.message);
    }
  };

  const deleteCategory = async (catIdx) => {
    if (!window.confirm('Delete category and all products?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'deleteCategory', password, catIndex: catIdx }),
      });
      if (res.ok) {
        fetchData();
      }
    } catch (e) {
      setError(e.message);
    }
  };

  const deleteProduct = async (catIdx, prodIdx) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'deleteProduct',
          password,
          catIndex: catIdx,
          prodIndex: prodIdx,
        }),
      });
      if (res.ok) {
        fetchData();
      }
    } catch (e) {
      setError(e.message);
    }
  };

  return (
    <div className="admin-section">
      <h2>Products Management</h2>
      
      <div className="add-category-form">
        <input
          type="text"
          placeholder="New category name"
          value={newCatName}
          onChange={(e) => setNewCatName(e.target.value)}
        />
        <button onClick={addCategory} disabled={addingCat}>
          <Plus size={18} /> Add Category
        </button>
      </div>

      {data.categories && data.categories.map((cat, catIdx) => (
        <div key={catIdx} className="category-card">
          <div 
            className="category-header"
            onClick={() => setExpandedCat(expandedCat === catIdx ? null : catIdx)}
          >
            <ChevronDown 
              size={20} 
              style={{ 
                transform: expandedCat === catIdx ? 'rotate(180deg)' : 'rotate(0deg)',
                transition: 'transform 0.3s'
              }} 
            />
            <h3>{cat.name || `Category ${catIdx}`}</h3>
            <button 
              className="delete-btn"
              onClick={(e) => {
                e.stopPropagation();
                deleteCategory(catIdx);
              }}
            >
              <Trash2 size={18} />
            </button>
          </div>

          <AnimatePresence>
            {expandedCat === catIdx && (
              <motion.div 
                className="category-products"
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
              >
                {cat.subProducts && cat.subProducts.map((prod, prodIdx) => (
                  <div key={prodIdx} className="product-item">
                    <div className="product-info">
                      <h4>{prod.name}</h4>
                      <p>{prod.description}</p>
                    </div>
                    <button 
                      className="delete-btn"
                      onClick={() => deleteProduct(catIdx, prodIdx)}
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      ))}
    </div>
  );
}

// ---------- GALLERY TAB ----------
function GalleryTab({ data, password, setError, fetchData }) {
  const [selectedFile, setSelectedFile] = useState(null);
  const [caption, setCaption] = useState('');
  const [uploading, setUploading] = useState(false);

  const handleUpload = async () => {
    if (!selectedFile) {
      setError('Please select an image');
      return;
    }

    const formData = new FormData();
    formData.append('password', password);
    formData.append('action', 'addGalleryImage');
    formData.append('caption', caption);
    formData.append('file', selectedFile);

    setUploading(true);
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        body: formData,
      });
      if (res.ok) {
        setSelectedFile(null);
        setCaption('');
        fetchData();
      } else {
        setError('Upload failed');
      }
    } catch (e) {
      setError(e.message);
    } finally {
      setUploading(false);
    }
  };

  const deleteGalleryImage = async (idx) => {
    if (!window.confirm('Delete this image?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'deleteGalleryImage',
          password,
          index: idx,
        }),
      });
      if (res.ok) {
        fetchData();
      }
    } catch (e) {
      setError(e.message);
    }
  };

  return (
    <div className="admin-section">
      <h2>Gallery Management</h2>

      <div className="upload-form">
        <div className="file-input-wrapper">
          <input
            type="file"
            accept="image/*"
            onChange={(e) => setSelectedFile(e.target.files?.[0])}
            disabled={uploading}
          />
          <span className="file-name">
            {selectedFile ? selectedFile.name : 'Choose image...'}
          </span>
        </div>
        <input
          type="text"
          placeholder="Image caption"
          value={caption}
          onChange={(e) => setCaption(e.target.value)}
        />
        <button onClick={handleUpload} disabled={uploading || !selectedFile}>
          <Upload size={18} /> {uploading ? 'Uploading...' : 'Upload'}
        </button>
      </div>

      <div className="gallery-grid">
        {data.gallery && data.gallery.map((item, idx) => (
          <motion.div 
            key={idx} 
            className="gallery-item"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            <img src={`${API_BASE}/${item.image}`} alt={item.caption} />
            <p>{item.caption}</p>
            <button 
              className="delete-btn"
              onClick={() => deleteGalleryImage(idx)}
            >
              <Trash2 size={16} />
            </button>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

// ---------- CLIENTS TAB ----------
function ClientsTab({ data, password, setError, fetchData }) {
  const [newClientName, setNewClientName] = useState('');
  const [adding, setAdding] = useState(false);

  const addClient = async () => {
    if (!newClientName.trim()) return;
    setAdding(true);
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'addClient',
          password,
          client: newClientName,
        }),
      });
      if (res.ok) {
        setNewClientName('');
        fetchData();
      } else {
        setError('Failed to add client');
      }
    } catch (e) {
      setError(e.message);
    } finally {
      setAdding(false);
    }
  };

  const deleteClient = async (idx) => {
    if (!window.confirm('Delete this client?')) return;
    try {
      const res = await fetch(`${API_BASE}/api/updateData`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'deleteClient',
          password,
          index: idx,
        }),
      });
      if (res.ok) {
        fetchData();
      }
    } catch (e) {
      setError(e.message);
    }
  };

  return (
    <div className="admin-section">
      <h2>Clients Management</h2>

      <div className="add-client-form">
        <input
          type="text"
          placeholder="Client name"
          value={newClientName}
          onChange={(e) => setNewClientName(e.target.value)}
          disabled={adding}
        />
        <button onClick={addClient} disabled={adding}>
          <Plus size={18} /> Add Client
        </button>
      </div>

      <div className="clients-list">
        {data.clients && data.clients.map((client, idx) => (
          <motion.div 
            key={idx} 
            className="client-item"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
          >
            <span>{client}</span>
            <button 
              className="delete-btn"
              onClick={() => deleteClient(idx)}
            >
              <Trash2 size={16} />
            </button>
          </motion.div>
        ))}
      </div>
    </div>
  );
}
